#!/usr/bin/env python3\n\nimport sys\nfrom pathlib import Path\n\n# Add current directory to path\ncurrent_dir = Path(__file__).parent\nif str(current_dir) not in sys.path:\n    sys.path.insert(0, str(current_dir))\n\nprint(\"🧠 SIMPLE COGNITIVE SYSTEM TEST\")\nprint(\"=\" * 40)\n\ntry:\n    from flee.SimulationSettings import SimulationSettings\n    from flee.flee import Person, Location\n    from flee import moving\n    \n    print(\"✅ Imports successful\")\n    \n    # Load settings\n    SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n    print(\"✅ Settings loaded\")\n    \n    # Enable cognitive system\n    SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n    SimulationSettings.move_rules[\"conflict_threshold\"] = 0.3\n    print(\"✅ Cognitive system enabled\")\n    \n    # Create test location and agent\n    location = Location(\"TestLocation\", 0, 0, 1000)\n    location.conflict_intensity = {1: 0.8}\n    location.time_of_conflict = 0\n    \n    agent = Person(location, attributes={\"connections\": 5})\n    print(\"✅ Agent created\")\n    \n    # Test cognitive pressure\n    pressure = agent.calculate_cognitive_pressure(time=1)\n    print(f\"✅ Cognitive pressure: {pressure:.3f}\")\n    \n    # Test System 2 capability\n    s2_capable = agent.get_system2_capable()\n    print(f\"✅ System 2 capable: {s2_capable}\")\n    \n    # Test move chance calculation\n    movechance, system2_active = moving.calculateMoveChance(agent, False, 1)\n    print(f\"✅ Move chance: {movechance:.3f}\")\n    print(f\"✅ System 2 active: {system2_active}\")\n    print(f\"✅ Agent state: {agent.cognitive_state}\")\n    \n    print(\"\\n🎉 All cognitive tests passed!\")\n    \nexcept Exception as e:\n    print(f\"❌ Error: {e}\")\n    import traceback\n    traceback.print_exc()\n"